  "Woher kommt Endometriose?",
  "Die Rolle von Fusobakterien bei der Entstehung von Endometriose",
  "Trans-Fettsäuren in der Ernährung bei Endometriose"
];

const baseStyle = "Modern health-tech vector illustration. Deep magenta, muted teal, soft pale pink. Minimalist, empathetic, text-free. Concept: ";

// 1. Drop your publishable key here (MUST start with pk_)
const apiKey = "pk_API_KEY_HERE"; 

return titles.map(title => {
  const prompt = encodeURIComponent(baseStyle + title);

  // 2. Note the new 'gen.pollinations.ai/image' endpoint and the '&key=' parameter
  const imageUrl = `https://gen.pollinations.ai/image/${prompt}?model=flux&width=1024&height=576&nologo=true&key=${apiKey}`;

  return { json: { title, imageUrl } };
});
